692	// hasTensorLayers checks if any layer has tensor media type.
693	func hasTensorLayers(layers []manifest.Layer) bool {
694		for _, layer := range layers {
695			if layer.MediaType == manifest.MediaTypeImageTensor {
696				return true
697			}
698		}
699		return false
700	}
