779		blobs := make([]transfer.Blob, len(layers))
780		for i, layer := range layers {
781			blobs[i] = transfer.Blob{
782				Digest: layer.Digest,
783				Size:   layer.Size,
784				From:   layer.From,
785			}
786		}
787	
788		srcDir, err := manifest.BlobsPath("")
789		if err != nil {
790			return err
791		}
792	
793		base := n.BaseURL()
794		if base.Scheme != "http" && regOpts != nil && regOpts.Insecure {
795			base.Scheme = "http"
796		}
797		baseURL := base.String()
798	
799		var totalSize int64
800		for _, blob := range blobs {
801			totalSize += blob.Size
802		}
803	
804		progress := func(completed, total int64) {
805			fn(api.ProgressResponse{
806				Status:    "pushing model",
807				Digest:    "sha256:model",
808				Total:     total,
809				Completed: completed,
810			})
811		}
812	
813		getToken := func(ctx context.Context, challenge transfer.AuthChallenge) (string, error) {
814			return getAuthorizationToken(ctx, registryChallenge{
815				Realm:   challenge.Realm,
816				Service: challenge.Service,
817				Scope:   challenge.Scope,
818			}, base.Host)
819		}
820	
821		return transfer.Upload(ctx, transfer.UploadOptions{
822			Blobs:       blobs,
823			BaseURL:     baseURL,
824			SrcDir:      srcDir,
825			Progress:    progress,
826			Token:       regOpts.Token,
827			GetToken:    getToken,
828			Logger:      slog.Default(),
829			Manifest:    manifestJSON,
830			ManifestRef: n.Tag,
831			Repository:  n.DisplayNamespaceModel(),
832		})
833	}
