835	func pullModelManifest(ctx context.Context, n model.Name, regOpts *registryOptions) (*manifest.Manifest, []byte, error) {
836		requestURL := n.BaseURL().JoinPath("v2", n.DisplayNamespaceModel(), "manifests", n.Tag)
837	
838		headers := make(http.Header)
839		headers.Set("Accept", "application/vnd.docker.distribution.manifest.v2+json")
840		resp, err := makeRequestWithRetry(ctx, http.MethodGet, requestURL, headers, nil, regOpts)
841		if err != nil {
842			return nil, nil, err
843		}
844		defer resp.Body.Close()
845	
846		data, err := io.ReadAll(resp.Body)
847		if err != nil {
848			return nil, nil, err
849		}
850	
851		var m manifest.Manifest
852		if err := json.Unmarshal(data, &m); err != nil {
853			return nil, nil, err
854		}
855	
856		return &m, data, err
857	}
