859	// GetSHA256Digest returns the SHA256 hash of a given buffer and returns it, and the size of buffer
860	func GetSHA256Digest(r io.Reader) (string, int64) {
861		h := sha256.New()
862		n, err := io.Copy(h, r)
863		if err != nil {
864			log.Fatal(err)
